    "triggers": [
      {
        "name": "TDTM_Opportunity",
        "object": "Opportunity",
        "events": [
          "after delete",
          "after insert",
          "after undelete",
          "after update",
          "before delete",
          "before insert",
          "before update"
        ],
        "handlers": [],
        "sourceUrl": "https://github.com/SalesforceFoundation/NPSP/blob/main/force-app/tdtm/triggers/TDTM_Opportunity.trigger",
        "description": "Master trigger on the Opportunity object that routes all donation events through the NPSP trigger dispatch framework. It contains no business logic itself but coordinates at least 10 registered handler classes covering Contact Role creation and soft credits, household member roles, Payment creation and sync, matching gift status updates, Campaign Member management, GAU allocation creation, Customizable Rollups, and cascade deletes. This single-trigger pattern is central to NPSP's architecture, providing a configurable, order-controlled execution pipeline for all donation-related automation. The source code This trigger routes all seven DML events (`before insert`, `before update`, `before delete`, `after insert`, `after update`, `after delete`, `after undelete`) on Opportunity to the TDTM framework dispatcher. It contains no business logic of its own; the handler dispatch table in `TDTM_Config_API` controls which of the registered handlers—including `OPP_OpportunityContactRoles_TDTM`, `PMT_Payment_TDTM`, `MTCH_Opportunity_TDTM`, `OPP_CampaignMember_TDTM`, `ALLO_Allocations_TDTM`, `CRLP_Rollup_TDTM`, and `OPP_CascadeDeleteLookups_TDTM`—execute for each event combination."
      },
      {
        "name": "TDTM_OpportunityContactRole",
        "object": "OpportunityContactRole",
        "events": [
          "after delete",
          "after insert",
          "after undelete",
          "after update",
          "before delete",
          "before insert",
          "before update"
        ],
        "handlers": [],
        "sourceUrl": "https://github.com/SalesforceFoundation/NPSP/blob/main/force-app/tdtm/triggers/TDTM_OpportunityContactRole.trigger",
        "description": "Master trigger on Contact Roles that routes all DML events through the TDTM framework, enabling handler classes to react when Contact Roles on donations are created, modified, or removed. NPSP creates one Contact Role per Contact per Opportunity following the precedence rules (Primary Contact > Honoree > Notification Recipient > Affiliated/Related > Household Member), and this trigger ensures soft credit and attribution logic fires consistently for all Contact Role changes — including those made by automated processes, data loaders, and manual user edits. The source code This trigger routes all seven DML events on the standard `OpportunityContactRole` object through the TDTM framework, enabling `OPP_AccountSoftCredit_TDTM` to react whenever OCRs are created, modified, or removed. Because Salesforce does not fire triggers on junction objects like OCRs in all deployment configurations, this trigger is necessary to ensure consistent attribution and soft-credit logic even when OCRs are managed by external integrations or data loaders."
      },
      {
        "name": "TDTM_Payment",
        "object": "npe01__OppPayment__c",
        "events": [
          "before insert",
          "before update",
          "before delete",
          "after insert",
          "after update",
          "after delete",
          "after undelete"
        ],
        "handlers": [],
        "sourceUrl": "https://github.com/SalesforceFoundation/NPSP/blob/main/force-app/tdtm/triggers/TDTM_Payment.trigger",
        "description": "Master trigger on Payment records that routes all payment events through the TDTM framework, enabling payment-level automation including bidirectional Opportunity-Payment synchronization, GAU Allocation cascade deletes, allocation creation when Payment Allocations are enabled, and rollup recalculation to Account, Contact, and GAU after payment state changes. All payment automation — currency enforcement, cascade deletes, allocation sync, and totals recalculation — runs through this single trigger entry point. The source code This trigger routes all seven DML events on `npe01__OppPayment__c` through the TDTM framework. The registered handlers include `PMT_Payment_TDTM` for bidirectional Opportunity-Payment synchronization and currency enforcement, `PMT_CascadeDeleteLookups_TDTM` for GAU Allocation cascade deletes, `ALLO_Allocations_TDTM` for allocation creation when Payment Allocations are enabled, and `CRLP_Rollup_TDTM` for recalculating hard-credit rollups to Account, Contact, and GAU after Payment state changes."
      }
    ],
