    "triggers": [
      {
        "name": "TDTM_RecurringDonation",
        "object": "npe03__Recurring_Donation__c",
        "events": [
          "after delete",
          "after insert",
          "after undelete",
          "after update",
          "before delete",
          "before insert",
          "before update"
        ],
        "handlers": [],
        "sourceUrl": "https://github.com/SalesforceFoundation/NPSP/blob/main/force-app/tdtm/triggers/TDTM_RecurringDonation.trigger",
        "description": "The Apex trigger on the Recurring Donation object that delegates all event processing to the NPSP Table-Driven Trigger Management (TDTM) framework. It fires on all seven DML events (before/after insert, update, delete, and after undelete) and routes execution to four registered TDTM handler classes: allocation currency sync, cascade delete with Closed/Won guard, the Legacy Opportunity lifecycle handler, and the Enhanced schedule modifications, validation, and field update handler. Only the handlers appropriate for the active Recurring Donation version execute. This trigger contains no business logic itself, following the NPSP pattern of centralizing trigger routing through TDTM. The source code This trigger fires on all seven DML events and contains no business logic, delegating entirely to four registered TDTM handler classes. The dual-handler registration — both RD_RecurringDonations_TDTM (Legacy) and RD2_RecurringDonations_TDTM (Enhanced) — means both handlers are evaluated on every RD DML event; each handler internally checks whether its respective mode is active before executing, making the TDTM dispatch table the switch point between Legacy and Enhanced processing."
      }
    ],
